mapper.select:
SELECT ro.*, rc.category_name
FROM repair_order ro
LEFT JOIN repair_category rc ON ro.category_id = rc.category_id

    AND ro.assigned_worker = #{workerId}
    AND ro.status = #{status}

ORDER BY ro.updated_time DESC
